def {{nama_fungsi}}(hostname):
    """Resolve hostname to IP addresses (IPv4 + IPv6).
    Returns dict with 'ipv4' and 'ipv6' lists."""
    results = {'ipv4': [], 'ipv6': []}
    try:
        infos = socket.getaddrinfo(hostname, None)
        for info in infos:
            family = info[0]
            addr = info[4][0]
            if family == socket.AF_INET:
                if addr not in results['ipv4']:
                    results['ipv4'].append(addr)
            elif family == socket.AF_INET6:
                if addr not in results['ipv6']:
                    results['ipv6'].append(addr)
    except socket.gaierror:
        pass
    return results

