    """Parse URL into components.
    Returns dict with scheme, host, port, path, query (dict), fragment.
    """
    parsed = urllib.parse.urlparse(url)
    query_params = dict(urllib.parse.parse_qsl(parsed.query))
    port = parsed.port
    if port is None:
        if parsed.scheme == 'https':
            port = 443
        elif parsed.scheme == 'http':
            port = 80
    return {
        'scheme': parsed.scheme,
        'host': parsed.hostname or '',
        'port': port,
        'path': parsed.path,
        'query': query_params,
        'fragment': parsed.fragment,
    }

def {{nama_fungsi}}(host, port, timeout={{timeout}}):
    """Check if host:port is reachable via TCP connect.
    Returns dict with 'reachable' (bool) and 'latency_ms' (float or None).
    """
    import time
    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    sock.settimeout(timeout)
    start = time.monotonic()
    try:
        sock.connect((host, port))
        elapsed = (time.monotonic() - start) * 1000
        sock.close()
        return {'reachable': True, 'latency_ms': round(elapsed, 2)}
    except (socket.timeout, socket.error, OSError):
        return {'reachable': False, 'latency_ms': None}
